var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"성황청 지원 함선, <color=#ffd34c>피에타</color> 함교","JPN":"聖皇庁支援艦船、<color=#ffd34c>ピエタ</color>艦橋","ENG":"Holy Curia Support ship <color=#ffd34c>Pieta</color>, Bridge","TWN":"聖皇廳支援艦船，<color=#ffd34c>聖殤</color>號艦橋","SCN":"圣廷支援舰船，<color=#ffd34c>圣母怜子</color>号舰桥","DEU":"Holy Curia Support ship <color=#ffd34c>Pieta</color>, Bridge","FRA":"Holy Curia Support ship <color=#ffd34c>Pieta</color>, Bridge"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"지정된 봉쇄 좌표의 좌표값 입력…….","JPN":"指定の封鎖座標を入力……","ENG":"Entering the designated sealing coordinates...","TWN":"輸入指定封鎖座標的座標值……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"쓰러스터 전부 개방! 이터니움 드라이브 기동률 15%, 34%, 72%……!","JPN":"スラスター全開放！　エタニウムドライブ起動率15％、34％、72％……！","ENG":"All thrusters open! Eternium Drive activation rate at 15%, 34%, 72%...!","TWN":"開放所有推進器！永恆之金引擎機動率15%，34%，72%……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"피에타! 주님의 은총 아래, 다이브하겠습니다!","JPN":"ピエタ！　主の恩寵の元、ダイブします！","ENG":"Pieta! Under God's grace, commencing dive!","TWN":"聖殤！在主的恩賜下，進行躍入！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"다이브 완료.","JPN":"ダイブ完了。","ENG":"Dive complete.","TWN":"躍入完成。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_121010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"일반 항행 모드로 전환합니다.","JPN":"一般航行モードに切り替えます。","ENG":"Switching to normal navigation mode.","TWN":"切換到正常航行模式。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_121010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_DISPATCHED","text":{"KOREA":"집행사제님, 지정된 봉쇄 좌표에 진입 완료하였습니다!","JPN":"執行司祭様、指定の封鎖座標に進入しました！","ENG":"We've entered the specified sealing coordinates, ma'am!","TWN":"執行祭司，已進入指定封鎖座標！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"심도가 무척 깊군요. 어떤 일이 일어나도 이상하지 않아요.","JPN":"深度が深いですね。ここでは何が起きてもおかしくない場所です。","ENG":"It is extremely deep. Anything can happen here.","TWN":"這個深度，發生什麼樣的事都不會覺得奇怪。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"자매님, 적성 반응 확인부터 부탁드리겠습니다.","JPN":"敵性反応の確認からお願いいたします。","ENG":"Sister, please check if there are any hostiles being detected.","TWN":"姊妹，請先確認是否有敵人反應。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_DISPATCHED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"함선 안에 예배당도 있는 거야?","JPN":"艦船の中に礼拝堂もあるのかよ？","ENG":"There's even a chapel inside the ship?","TWN":"艦船裡面也有禮拜堂嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 살다살다 성황청 함선을 빌려 타게 될 줄은 몰랐네.","JPN":"ったく、聖皇庁の艦船に乗ることになるとはな。","ENG":"Blimey. Who would've thought I'd be on a Holy Curia ship, eh?","TWN":"真是的，沒想到我有生之年會坐上聖皇廳的艦船。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"원래 불신자들은 탑승할 수 없는 함선입니다만.","JPN":"本来なら不信者は搭乗できない艦船ですが……","ENG":"Normally, we do not allow nonbelievers to be on board.","TWN":"非信徒本是無法乘坐這個艦船的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"한시가 급한 일이니, 특별히 동승을 허가해드렸습니다. 나중에 고해성사라도 해야겠군요.","JPN":"一刻を争う状況ですので、特別同乗を許可しました。告解扱いです。","ENG":"But since this is an urgent matter, I will especially allow it this time. I should make a confession about this later.","TWN":"但現在刻不容緩，所以特意准你同乘。以後再對此進行懺悔吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"학회 측 추종자인 당신은 필히 소속과 신분을 숨기도록 하세요.","JPN":"あなたは学会側の人間ですから、所属と身分が認知されないように気をつけてください。","ENG":"Follower of the Society, you must hide your identity no matter what.","TWN":"你身為學會方面的追隨者，請務必隱瞞所屬和身分。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그럼~ 내가 레지나 명령으로 여기 왔다는 건 아무한테도 말 안 할게!","JPN":"もちろん～レジーナの命令でここに来てるって、誰にも言わないから！","ENG":"Then, I won't tell a soul that I'm here on Regina's orders!","TWN":"當然了～我才不會告訴任何人我是奉蕾佳娜命令來到這裡的！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하아, 당신과 이야기를 나누고 있으면 시스터 루퍼가 그리워질 지경이군요.","JPN":"はあ……あなたと会話していると、シスター・ルーパーが恋しくなります。","ENG":"*Sigh.* Talking with you makes me miss Sister Looper.","TWN":"哈啊，和你聊天，總是能讓我想念洛珀姊妹。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"집행사제님, 방패 용병단 1개 중대 성무 집행 준비를 마쳤습니다.","JPN":"執行司祭様、盾傭兵団1個中隊の聖務執行準備が整いました。","ENG":"Ma'am, a company of Shield Mercenary has finished preparations for the sacred mission.","TWN":"執行祭司，盾牌傭兵團的一個中隊已做好執行聖務的準備。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"언제든 말씀만 해주십시오. 주님의 이름 아래 싹 쓸어버리겠습니다.","JPN":"いつでも指示を出してください。主の名の元に全部蹴散らしてみせます。","ENG":"Just say the word. We'll cleanse the place under the Lord's name.","TWN":"請隨時下令。我們會以神的名義，將敵人全數清除。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오늘 성무의 주요 목적은 수색입니다. 되도록 전투는 피해주세요.","JPN":"本日の聖務の主な目的は捜索です。なるべく戦闘は避けるように。","ENG":"The objective of today's sacred mission is reconnaissance. Please try to refrain from combat.","TWN":"今天聖務的主要目的是搜索，所以要盡量避免戰鬥。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그보다 버넷 요원. 기관의 지원은 언제쯤 도착하죠?","JPN":"それより、エージェント・バーネット。機関の支援はいつ頃着く予定ですか？","ENG":"And Agent Burnett. When do you think the Institution's reinforcements will arrive?","TWN":"對了，伯內特，機關的支援什麼時候能到？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};